import requests, re, os, json

# the following function will fetch the latest list of 100+ top websites from GitHub
def getWebsiteList(url):

    r = requests.get(url)
    s = str(r.content).replace("\\r\\n", " ") #replace linebreaks
    s = re.sub('<[^>]+>', '', s)              #remove HTML elements
    s = [x for x in s.split() if not ":" == x]  #get rid of :'s

    return len(set(s))

if __name__=="__main__":

    url = "https://github.com/topics"
    site = getWebsiteList(url)
    print (site)

#the following code will fetch the first 10 pages of each website's page. We use the requests module to retrieve and format our webpage. Then, we use regular expressions to extract URLs that meet our search criteria. Finally, we convert these URLs into sets for the final comparison
def getPageURLs(url):

    r = requests.get(url)
    s = str(r.content).replace("\\r\\n", " ") #replace linebreaks
    s = re.sub('<[^>]+>', '', s)              #remove HTML elements
    urls = [x for x in set(re.findall('http[s]?://(?:[a-zA-Z]|[0-9]|[$-_@.&+]|[!*\(\),]|(?:%[0-9a-fA-F][0-9a-fA-F]))+', s))] #extract URLs that meet criteria. Set will eliminate duplicates
    urls = set(re.sub('[^a-zA-Z0-9\s\.\/\_]', '', url) for x in urls if len(x)==len(url))   #remove punctuation and symbols. Restrict to alphanumeric

    return list(urls)[0:10]

if __name__=="__main__":
    
    url = "https://github.com/"
    urls = getPageURLs(url)
    print (urls)